import{_ as e,o as i,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"SwiftList 简介","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/introduction.md","filePath":"zh-CN/guide/introduction.md"}'),s={name:"zh-CN/guide/introduction.md"};function a(n,t,l,d,c,f){return i(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="swiftlist-简介" tabindex="-1">SwiftList 简介 <a class="header-anchor" href="#swiftlist-简介" aria-label="Permalink to &quot;SwiftList 简介&quot;">​</a></h1><p>SwiftList 是一款针对 Windows 系统设计的高性能、低消耗、可扩展的全局检索工具，旨在作为 <strong>Listary</strong> 的高颜值、支持深度定制的开源替代方案。它能以极快的速度建立和维护本地物理文件索引，并提供开放的插件 SDK 方便开发者扩展各项功能。</p><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><p>SwiftList 提供官方打包的安装器与免安装便携版（最新稳定版）：</p><ul><li>💾 <strong><a href="https://github.com/SwiftList/SwiftList/releases/latest/download/SwiftList-Setup.exe" target="_blank" rel="noreferrer">下载安装包</a></strong> — 全功能安装包（支持开机自启和 Windows 服务后台运行）。</li><li>📦 <strong><a href="https://github.com/SwiftList/SwiftList/releases/latest/download/SwiftList-Portable.zip" target="_blank" rel="noreferrer">下载便携版</a></strong> — 绿色免安装，解压即用。</li><li>🔍 或者前往 <strong><a href="https://github.com/SwiftList/SwiftList/releases" target="_blank" rel="noreferrer">GitHub Releases 历史版本页面</a></strong> 查看所有发布版本。</li></ul><h2 id="核心设计理念" tabindex="-1">核心设计理念 <a class="header-anchor" href="#核心设计理念" aria-label="Permalink to &quot;核心设计理念&quot;">​</a></h2><ol><li><strong>YAGNI (You Aren&#39;t Gonna Need It)</strong>：拒绝繁琐的多余设计，保持逻辑的简洁与代码的高效。</li><li><strong>多进程与架构隔离</strong>： <ul><li><strong><code>SwiftList.Service</code> (系统服务 - <code>--service</code>)</strong>：运行在 Session 0 的 Windows 服务，直接对接 NTFS MFT 和 USN 日志进行索引数据库维护，全局共享。</li><li><strong><code>SwiftList.Service</code> (钩子进程 - <code>--hook</code>)</strong>：运行在用户会话中，拦截全局系统热键并动态搜集活动窗口的焦点与物理路径。</li><li><strong><code>SwiftList.App</code> (用户界面)</strong>：运行在用户会话中的 WPF 应用程序，承载界面交互、展示搜索结果，并按需加载用户私有插件。</li></ul></li><li><strong>极速 FZF 模糊匹配</strong>：采用优化的匹配算法，支持 FZF 模糊搜索、拼音首字母缩写、以及插件提供的丰富别名检索。</li></ol>',7)])])}const u=e(s,[["render",a]]);export{h as __pageData,u as default};
